1	package network
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"fmt"
8		"strings"
9		"sync"
10		"time"
11	
12		"github.com/pedronauck/agh/internal/store"
13	)
14	
15	var (
16		// ErrLocalPeerNotFound reports an unknown local session sender.
17		ErrLocalPeerNotFound = errors.New("network: local peer not found")
18		// ErrTargetPeerNotFound reports a directed send target missing from presence.
19		ErrTargetPeerNotFound = errors.New("network: target peer not found")
20		// ErrDuplicateEnvelope reports a replay-window duplicate.
21		ErrDuplicateEnvelope = errors.New("network: duplicate envelope")
22		// ErrEnvelopeNotTarget reports a directed envelope for a peer this daemon does not own.
23		ErrEnvelopeNotTarget = errors.New("network: envelope not targeted to a local peer")
24	)
25	
26	// RouterTransport is the narrow publish surface consumed by the router.
27	type RouterTransport interface {
28		Publish(ctx context.Context, subject string, payload []byte) error
29	}
30	
31	// SendRequest carries one caller-supplied outbound envelope request.
32	type SendRequest struct {
33		SessionID     string
34		Channel       string
35		Kind          Kind
36		To            *string
37		Body          json.RawMessage
38		InteractionID *string
39		ReplyTo       *string
40		TraceID       *string
41		CausationID   *string
42		ExpiresAt     *int64
43		ID            *string
44		Ext           ExtensionMap
45	}
46	
47	// SendResult summarizes one outbound publish.
48	type SendResult struct {
49		ID       string
50		Subject  string
51		Envelope Envelope
52	}
53	
54	// Delivery is one accepted inbound message delivery target.
55	type Delivery struct {
56		SessionID string
57		PeerID    string
58		Envelope  Envelope
59	}
60	
61	// RouteResult is the router decision for one inbound envelope.
62	type RouteResult struct {
63		Envelope   *Envelope
64		Deliveries []Delivery
65		Generated  []Envelope
66		Duplicate  bool
67		Ignored    bool
68		Rejected   bool
69		ReasonCode *ReasonCode
70	}
71	
72	// Heartbeat owns one periodic greet publisher.
73	type Heartbeat struct {
74		stop chan struct{}
75		done chan struct{}
76		once sync.Once
77	}
78	
79	// Stop cancels the heartbeat and waits for its goroutine to exit.
80	func (h *Heartbeat) Stop() {
81		if h == nil {
82			return
83		}
84	
85		h.once.Do(func() {
86			if h.stop != nil {
87				close(h.stop)
88			}
89		})
90		<-h.done
91	}
92	
93	// Done returns the heartbeat completion signal.
94	func (h *Heartbeat) Done() <-chan struct{} {
95		if h == nil {
96			return nil
97		}
98		return h.done
99	}
100	
101	// RouterOption customizes router construction.
102	type RouterOption func(*Router)
103	
104	// WithRouterClock overrides the clock used for send and receive decisions.
105	func WithRouterClock(now func() time.Time) RouterOption {
106		return func(router *Router) {
107			router.now = now
108		}
109	}
110	
111	// Router handles outbound subject selection plus inbound receiver policy.
112	type Router struct {
113		peers        *PeerRegistry
114		transport    RouterTransport
115		maxReplayAge time.Duration
116		now          func() time.Time
117	
118		mu           sync.Mutex
119		seen         map[string]time.Time
120		interactions map[string]Interaction
121	}
122	
123	type receiveState struct {
124		result            RouteResult
125		envelope          Envelope
126		directedTarget    LocalPeer
127		hasDirectedTarget bool
128		now               time.Time
129	}
130	
131	// NewRouter constructs the routing runtime on top of a peer registry.
132	func NewRouter(
133		peers *PeerRegistry,
134		transport RouterTransport,
135		maxReplayAge time.Duration,
136		opts ...RouterOption,
137	) (*Router, error) {
138		if peers == nil {
139			return nil, fmt.Errorf("%w: peer registry is required", ErrInvalidField)
140		}
141		if maxReplayAge <= 0 {
142			maxReplayAge = DefaultMaxReplayAge
143		}
144	
145		router := &Router{
146			peers:        peers,
147			transport:    transport,
148			maxReplayAge: maxReplayAge,
149			now:          func() time.Time { return time.Now().UTC() },
150			seen:         make(map[string]time.Time),
151			interactions: make(map[string]Interaction),
152		}
153		for _, opt := range opts {
154			if opt != nil {
155				opt(router)
156			}
157		}
158		if router.now == nil {
159			router.now = func() time.Time { return time.Now().UTC() }
160		}
161	
162		return router, nil
163	}
164	
165	// Leave removes the local sender presence for one session.
166	func (r *Router) Leave(sessionID string) (LocalPeer, bool) {
167		if r == nil || r.peers == nil {
168			return LocalPeer{}, false
169		}
170		return r.peers.LeaveLocal(sessionID)
171	}
172	
173	// PublishGreet advertises one local peer card to its joined channel.
174	func (r *Router) PublishGreet(ctx context.Context, sessionID string, summary string) (SendResult, error) {
175		if r == nil || r.peers == nil {
176			return SendResult{}, fmt.Errorf("%w: router peer registry is required", ErrInvalidField)
177		}
178	
179		local, ok := r.peers.LocalBySession(sessionID)
180		if !ok {
181			return SendResult{}, fmt.Errorf("%w: session=%q", ErrLocalPeerNotFound, strings.TrimSpace(sessionID))
182		}
183	
184		body, err := json.Marshal(GreetBody{
185			PeerCard: clonePeerCard(local.PeerCard),
186			Summary:  ResolveGreetSummary(local.PeerCard, summary),
187		})
188		if err != nil {
189			return SendResult{}, fmt.Errorf("network: marshal greet body: %w", err)
190		}
191	
192		return r.Send(ctx, SendRequest{
193			SessionID: local.SessionID,
194			Channel:   local.Channel,
195			Kind:      KindGreet,
196			Body:      body,
197		})
198	}
199	
200	// StartHeartbeat publishes greet immediately, then keeps re-greeting on the configured interval.
201	func (r *Router) StartHeartbeat(ctx context.Context, sessionID string, summary string) (*Heartbeat, error) {
202		if ctx == nil {
203			return nil, errors.New("network: heartbeat context is required")
204		}
205		if r == nil || r.peers == nil {
206			return nil, fmt.Errorf("%w: router peer registry is required", ErrInvalidField)
207		}
208	
209		interval := r.peers.GreetInterval()
210		if interval <= 0 {
211			return nil, fmt.Errorf("%w: greet interval must be positive", ErrInvalidField)
212		}
213		if _, err := r.PublishGreet(ctx, sessionID, summary); err != nil {
214			return nil, err
215		}
216	
217		heartbeat := &Heartbeat{
218			stop: make(chan struct{}),
219			done: make(chan struct{}),
220		}
221	
222		go func() {
223			defer close(heartbeat.done)
224	
225			ticker := time.NewTicker(interval)
226			defer ticker.Stop()
227	
228			for {
229				select {
230				case <-heartbeat.stop:
231					return
232				case <-ctx.Done():
233					return
234				case <-ticker.C:
235					if _, err := r.PublishGreet(
236						ctx,
237						sessionID,
238						summary,
239					); err != nil &&
240						errors.Is(err, ErrLocalPeerNotFound) {
241						return
242					}
243				}
244			}
245		}()
246	
247		return heartbeat, nil
248	}
249	
250	// Send validates one outbound request, enforces presence preflight, and publishes it.
251	func (r *Router) Send(ctx context.Context, req SendRequest) (SendResult, error) {
252		if ctx == nil {
253			return SendResult{}, errors.New("network: send context is required")
254		}
255		if r == nil {
256			return SendResult{}, errors.New("network: router is required")
257		}
258	
259		now := r.now().UTC()
260		envelope, err := r.buildEnvelope(req, now)
261		if err != nil {
262			return SendResult{}, err
263		}
264		if envelope.IsDirected() && !r.peers.HasPresence(envelope.Channel, *envelope.To, now) {
265			return SendResult{}, fmt.Errorf(
266				"%w: peer_id=%q channel=%q",
267				ErrTargetPeerNotFound,
268				*envelope.To,
269				envelope.Channel,
270			)
271		}
272		if err := r.validateSendLifecycle(envelope, now); err != nil {
273			return SendResult{}, err
274		}
275	
276		subject, err := subjectForEnvelope(envelope)
277		if err != nil {
278			return SendResult{}, err
279		}
280		if err := r.publishEnvelope(ctx, envelope); err != nil {
281			return SendResult{}, err
282		}
283		r.syncSentLifecycle(envelope, now)
284	
285		return SendResult{
286			ID:       envelope.ID,
287			Subject:  subject,
288			Envelope: envelope,
289		}, nil
290	}
291	
292	// Receive validates one inbound envelope, updates presence, and returns delivery decisions.
293	func (r *Router) Receive(ctx context.Context, payload []byte) (RouteResult, error) {
294		if ctx == nil {
295			return RouteResult{}, errors.New("network: receive context is required")
296		}
297		if r == nil {
298			return RouteResult{}, errors.New("network: router is required")
299		}
300	
301		now := r.now().UTC()
302		envelope, err := ParseEnvelope(payload, ValidateOptions{Now: now, MaxReplayAge: r.maxReplayAge})
303		if err != nil {
304			return r.handleReceiveParseError(ctx, payload, now, err)
305		}
306	
307		state, done, err := r.prepareReceiveState(ctx, envelope, now)
308		if err != nil {
309			return RouteResult{}, err
310		}
311		if done {
312			return state.result, nil
313		}
314		return r.dispatchReceivedEnvelope(ctx, state)
315	}
316	
317	func (r *Router) handleReceiveParseError(
318		ctx context.Context,
319		payload []byte,
320		now time.Time,
321		parseErr error,
322	) (RouteResult, error) {
323		reason := reasonCodeForReceiveError(parseErr)
324		result := RouteResult{
325			Rejected:   true,
326			ReasonCode: &reason,
327		}
328		partial := parseEnvelopeSummary(payload)
329		if partial == nil {
330			return result, nil
331		}
332		result.Envelope = partial
333		if partial.Kind != KindDirect {
334			return result, nil
335		}
336	
337		directedTarget, ok, err := r.resolveDirectedTarget(*partial)
338		if err != nil {
339			return RouteResult{}, err
340		}
341		if !ok {
342			return result, nil
343		}
344		status, emit := rejectionReceiptStatus(reason)
345		result, _, err = r.appendPublishedReceipt(ctx, result, directedTarget, *partial, now, status, emit)
346		return result, err
347	}
348	
349	func (r *Router) prepareReceiveState(
350		ctx context.Context,
351		envelope Envelope,
352		now time.Time,
353	) (receiveState, bool, error) {
354		state := receiveState{
355			result:   RouteResult{Envelope: &envelope},
356			envelope: envelope,
357			now:      now,
358		}
359		directedTarget, ok, err := r.resolveDirectedTarget(envelope)
360		if err != nil {
361			return receiveState{}, false, err
362		}
363		state.directedTarget = directedTarget
364		state.hasDirectedTarget = ok
365		if envelope.IsDirected() && !ok {
366			reason := ReasonCodeNotTarget
367			state.result.Rejected = true
368			state.result.ReasonCode = &reason
369			return state, true, nil
370		}
371		if !r.markSeen(envelope, now) {
372			return state, false, nil
373		}
374	
375		reason := ReasonCodeDuplicate
376		state.result.Duplicate = true
377		state.result.Rejected = true
378		state.result.ReasonCode = &reason
379		if envelope.Kind != KindDirect || !ok {
380			return state, true, nil
381		}
382	
383		result, _, err := r.appendPublishedReceipt(
384			ctx,
385			state.result,
386			directedTarget,
387			envelope,
388			now,
389			ReceiptStatusDuplicate,
390			true,
391		)
392		if err != nil {
393			return receiveState{}, false, err
394		}
395		state.result = result
396		return state, true, nil
397	}
398	
399	func (r *Router) dispatchReceivedEnvelope(ctx context.Context, state receiveState) (RouteResult, error) {
400		switch state.envelope.Kind {
401		case KindGreet:
402			return r.handleReceivedGreet(state)
403		case KindWhois:
404			return r.handleWhois(
405				ctx,
406				state.envelope,
407				state.result,
408				state.directedTarget,
409				state.hasDirectedTarget,
410				state.now,
411			)
412		case KindSay:
413			state.result.Deliveries = deliveriesFromLocalPeers(r.peers.LocalPeers(state.envelope.Channel), state.envelope)
414			return state.result, nil
415		case KindCapability:
416			return r.handleReceivedCapability(ctx, state)
417		case KindDirect, KindReceipt, KindTrace:
418			return r.handleReceivedLifecycle(ctx, state)
419		default:
420			reason := ReasonCodeUnsupportedKind
421			state.result.Rejected = true
422			state.result.ReasonCode = &reason
423			return state.result, nil
424		}
425	}
