559	func (r *Router) handleWhois(
560		ctx context.Context,
561		envelope Envelope,
562		result RouteResult,
563		directedTarget LocalPeer,
564		hasDirectedTarget bool,
565		now time.Time,
566	) (RouteResult, error) {
567		body, err := envelope.DecodeBody()
568		if err != nil {
569			return RouteResult{}, err
570		}
571		whois, ok := body.(WhoisBody)
572		if !ok {
573			return RouteResult{}, fmt.Errorf("network: unexpected whois body type %T", body)
574		}
575	
576		switch whois.Type {
577		case WhoisTypeResponse:
578			if whois.PeerCard != nil {
579				capabilityCatalog, capabilityCatalogKnown := decodeWhoisCapabilityCatalogResponseExt(envelope.Ext)
580				if _, _, refreshErr := r.peers.RefreshRemoteWithCapabilityCatalog(
581					envelope.Channel,
582					*whois.PeerCard,
583					capabilityCatalog,
584					capabilityCatalogKnown,
585					now,
586				); refreshErr != nil {
587					return RouteResult{}, refreshErr
588				}
589			}
590			if hasDirectedTarget {
591				if delivery, ok := deliveryFromLocalPeer(directedTarget, envelope); ok {
592					result.Deliveries = []Delivery{delivery}
593				}
594			}
595			return result, nil
596		case WhoisTypeRequest:
597			return r.handleWhoisRequest(ctx, envelope, result, whois, directedTarget, hasDirectedTarget, now)
598		default:
599			reason := ReasonCodeMalformed
600			result.Rejected = true
601			result.ReasonCode = &reason
602			return result, nil
603		}
604	}
605	
606	func (r *Router) handleWhoisRequest(
607		ctx context.Context,
608		envelope Envelope,
609		result RouteResult,
610		whois WhoisBody,
611		directedTarget LocalPeer,
612		hasDirectedTarget bool,
613		now time.Time,
614	) (RouteResult, error) {
615		discoveryRequest := parseWhoisCapabilityDiscoveryRequest(envelope.Ext)
616		if envelope.IsDirected() && hasDirectedTarget && isEnvelopeSender(directedTarget, envelope) {
617			result.Ignored = true
618			return result, nil
619		}
620		responders := r.whoisRequestResponders(envelope, whois, directedTarget, hasDirectedTarget)
621	
622		for _, responder := range responders {
623			reply, err := r.buildWhoisResponseEnvelope(envelope, responder, discoveryRequest, now)
624			if err != nil {
625				return RouteResult{}, err
626			}
627			result.Generated = append(result.Generated, reply)
628		}
629		if len(result.Generated) > 0 {
630			if err := r.publishGenerated(ctx, result.Generated); err != nil {
631				return RouteResult{}, err
632			}
633		}
634		return result, nil
635	}
636	
637	func (r *Router) whoisRequestResponders(
638		envelope Envelope,
639		whois WhoisBody,
640		directedTarget LocalPeer,
641		hasDirectedTarget bool,
642	) []LocalPeer {
643		if envelope.IsDirected() {
644			if hasDirectedTarget && !isEnvelopeSender(directedTarget, envelope) {
645				return []LocalPeer{directedTarget}
646			}
647			return nil
648		}
649		matches := r.peers.MatchLocalPeers(envelope.Channel, whois.Query)
650		responders := make([]LocalPeer, 0, len(matches))
651		for _, peer := range matches {
652			if isEnvelopeSender(peer, envelope) {
653				continue
654			}
655			responders = append(responders, peer)
656		}
657		return responders
658	}
659	
660	func (r *Router) buildWhoisResponseEnvelope(
661		request Envelope,
662		responder LocalPeer,
663		discoveryRequest whoisCapabilityDiscoveryRequest,
664		now time.Time,
665	) (Envelope, error) {
666		responseCard := clonePeerCard(responder.PeerCard)
667		if len(responder.CapabilityCatalog) != 0 {
668			responseCatalog := responder.CapabilityCatalog
669			if discoveryRequest.includeCapabilityCatalog {
670				responseCatalog = selectWhoisCapabilityCatalog(
671					responder.CapabilityCatalog,
672					discoveryRequest.capabilityIDs,
673				)
674			}
675			if err := applyCapabilityBriefProjection(&responseCard, responseCatalog); err != nil {
676				return Envelope{}, err
677			}
678		}
679	
680		payload, err := marshalEnvelopeBody(WhoisBody{
681			Type:     WhoisTypeResponse,
682			PeerCard: &responseCard,
683		})
684		if err != nil {
685			return Envelope{}, err
686		}
687		responseExt, err := buildWhoisCapabilityCatalogResponseExt(
688			discoveryRequest,
689			responder.CapabilityCatalog,
690		)
691		if err != nil {
692			return Envelope{}, err
693		}
694	
695		reply := Envelope{
696			Protocol: ProtocolV0,
697			ID:       store.NewID("msg"),
698			Kind:     KindWhois,
699			Channel:  request.Channel,
700			From:     responder.PeerID,
701			To:       ptrString(request.From),
702			ReplyTo:  ptrString(request.ID),
703			TS:       now.Unix(),
704			Body:     payload,
705			Proof:    nil,
706			Ext:      responseExt,
707		}
708		if err := ValidateEnvelope(reply, ValidateOptions{Now: now, MaxReplayAge: r.maxReplayAge}); err != nil {
709			return Envelope{}, err
710		}
711		if err := ensureEnvelopeSizeLimit(reply); err != nil {
712			return Envelope{}, err
713		}
714		return reply, nil
715	}
