782	func (r *Router) markSeen(envelope Envelope, now time.Time) bool {
783		r.mu.Lock()
784		defer r.mu.Unlock()
785	
786		for id, expiresAt := range r.seen {
787			if !expiresAt.After(now) {
788				delete(r.seen, id)
789			}
790		}
791		if expiresAt, ok := r.seen[envelope.ID]; ok && expiresAt.After(now) {
792			return true
793		}
794		r.seen[envelope.ID] = replayDeadline(envelope, now, r.maxReplayAge)
795		return false
796	}
