798	func (r *Router) applyLifecycle(envelope Envelope, now time.Time) (LifecycleResult, error) {
799		key := interactionKey(envelope.Channel, *envelope.InteractionID)
800	
801		r.mu.Lock()
802		defer r.mu.Unlock()
803	
804		result, err := r.evaluateLifecycleLocked(key, envelope, now)
805		if err != nil {
806			return LifecycleResult{}, err
807		}
808		r.interactions[key] = result.Interaction
809		return result, nil
810	}
