812	func (r *Router) evaluateLifecycle(envelope Envelope, now time.Time) (LifecycleResult, error) {
813		key := interactionKey(envelope.Channel, *envelope.InteractionID)
814	
815		r.mu.Lock()
816		defer r.mu.Unlock()
817	
818		return r.evaluateLifecycleLocked(key, envelope, now)
819	}
