821	func (r *Router) evaluateLifecycleLocked(
822		key string,
823		envelope Envelope,
824		now time.Time,
825	) (LifecycleResult, error) {
826		current, ok := r.interactions[key]
827		var currentPtr *Interaction
828		if ok {
829			copied := current
830			currentPtr = &copied
831		}
832	
833		return ApplyInteractionEnvelope(currentPtr, envelope, now)
834	}
