836	func (r *Router) validateSendLifecycle(envelope Envelope, now time.Time) error {
837		if !shouldTrackSentLifecycle(envelope) {
838			return nil
839		}
840	
841		result, err := r.evaluateLifecycle(envelope, now)
842		if err != nil {
843			return err
844		}
845		switch result.Action {
846		case LifecycleActionIgnored, LifecycleActionRejectDirect:
847			return fmt.Errorf(
848				"%w: interaction_id=%q kind=%q",
849				ErrInteractionClosed,
850				result.Interaction.ID,
851				envelope.Kind,
852			)
853		default:
854			return nil
855		}
856	}
