858	func (r *Router) syncSentLifecycle(envelope Envelope, now time.Time) {
859		if !shouldTrackSentLifecycle(envelope) {
860			return
861		}
862		if !r.shouldSyncSentLifecycle(envelope) {
863			return
864		}
865	
866		if _, err := r.applyLifecycle(envelope, now); err != nil {
867			return
868		}
869	}
