933	func replayDeadline(envelope Envelope, now time.Time, maxReplayAge time.Duration) time.Time {
934		deadline := time.Unix(envelope.TS, 0).Add(maxReplayAge).UTC()
935		if envelope.ExpiresAt != nil {
936			expiresAt := time.Unix(*envelope.ExpiresAt, 0).UTC()
937			if expiresAt.Before(deadline) {
938				deadline = expiresAt
939			}
940		}
941		minDeadline := time.Unix(now.Unix()+1, 0).UTC()
942		if deadline.Before(minDeadline) {
943			return minDeadline
944		}
945		return deadline
946	}
