996		body := ReceiptBody{
997			ForID:      envelope.ID,
998			Status:     status,
999			ReasonCode: &reason,
1000			Detail:     detail,
1001		}
1002		payload, err := marshalEnvelopeBody(body)
1003		if err != nil {
1004			return Envelope{}, false, err
1005		}
1006		receipt := Envelope{
1007			Protocol:      ProtocolV0,
1008			ID:            store.NewID("msg"),
1009			Kind:          KindReceipt,
1010			Channel:       envelope.Channel,
1011			From:          local.PeerID,
1012			To:            ptrString(envelope.From),
1013			InteractionID: ptrString(*envelope.InteractionID),
1014			ReplyTo:       ptrString(envelope.ID),
1015			TS:            now.Unix(),
1016			Body:          payload,
1017		}
1018		return receipt, true, nil
1019	}
