1034	func parseEnvelopeSummary(data []byte) *Envelope {
1035		var env Envelope
1036		if err := json.Unmarshal(data, &env); err != nil {
1037			return nil
1038		}
1039	
1040		return &Envelope{
1041			Protocol:      strings.TrimSpace(env.Protocol),
1042			ID:            strings.TrimSpace(env.ID),
1043			Kind:          Kind(strings.TrimSpace(string(env.Kind))),
