523	func sortedNetworkChannelPayloads(
524		aggregates map[string]*networkChannelAggregate,
525	) []contract.NetworkChannelPayload {
526		channels := make([]contract.NetworkChannelPayload, 0, len(aggregates))
527		for _, aggregate := range aggregates {
528			if aggregate == nil {
529				continue
530			}
531			channels = append(channels, networkChannelPayloadFromAggregate(aggregate))
532		}
533		sort.Slice(channels, func(i int, j int) bool {
534			left := networkChannelSortTimestamp(channels[i])
535			right := networkChannelSortTimestamp(channels[j])
536			switch {
537			case left != nil && right != nil && !left.Equal(*right):
538				return left.After(*right)
539			case left != nil && right == nil:
540				return true
541			case left == nil && right != nil:
542				return false
543			case channels[i].MessageCount != channels[j].MessageCount:
544				return channels[i].MessageCount > channels[j].MessageCount
545			default:
546				return channels[i].Channel < channels[j].Channel
547			}
548		})
549		return channels
550	}
551	
552	func networkChannelSortTimestamp(channel contract.NetworkChannelPayload) *time.Time {
553		switch {
554		case channel.LastActivityAt == nil:
555			return channel.LastPresenceAt
556		case channel.LastPresenceAt == nil:
557			return channel.LastActivityAt
558		case channel.LastPresenceAt.After(*channel.LastActivityAt):
559			return channel.LastPresenceAt
560		default:
561			return channel.LastActivityAt
562		}
563	}
