576	func applyNetworkChannelSessions(
577		aggregates map[string]*networkChannelAggregate,
578		sessions []*session.Info,
579	) {
580		for _, info := range sessions {
581			if !networkChannelSessionVisible(info) {
582				continue
583			}
584			aggregate := ensureNetworkChannelAggregate(aggregates, info.Channel)
585			aggregate.sessionCount++
586		}
587	}
