589	func applyNetworkChannelPeers(
590		aggregates map[string]*networkChannelAggregate,
591		peers []network.PeerInfo,
592	) {
593		for _, peer := range peers {
594			aggregate := ensureNetworkChannelAggregate(aggregates, peer.Channel)
595			aggregate.peerCount++
596			if peer.Local {
597				aggregate.localPeerCount++
598				continue
599			}
600			aggregate.remotePeerCount++
601		}
602	}
603	
604	func applyNetworkChannelMessages(
605		aggregates map[string]*networkChannelAggregate,
606		messages []store.NetworkMessageEntry,
607	) {
608		for _, message := range messages {
609			aggregate := ensureNetworkChannelAggregate(aggregates, message.Channel)
610			aggregate.recordHistoricalParticipant(message.PeerFrom)
611			aggregate.recordHistoricalParticipant(message.PeerTo)
612			if !isPublicChannelTimelineMessage(message) {
613				continue
614			}
615			if isPresenceMessage(message) {
616				aggregate.presenceCount++
617				aggregate.lastPresenceAt = laterTimePtr(aggregate.lastPresenceAt, message.Timestamp)
618				continue
619			}
620			aggregate.messageCount++
621			aggregate.lastActivityAt = laterTimePtr(aggregate.lastActivityAt, message.Timestamp)
622			aggregate.lastMessageAt = laterTimePtr(aggregate.lastMessageAt, message.Timestamp)
623			if preview := networkMessagePreview(message); preview != "" && aggregateMessageIsLatest(aggregate, message) {
624				aggregate.lastMessagePreview = preview
625			}
626		}
627	}
628	
629	func (a *networkChannelAggregate) recordHistoricalParticipant(peerID string) {
630		if a == nil {
631			return
632		}
633		trimmed := strings.TrimSpace(peerID)
634		if trimmed == "" {
635			return
636		}
637		if a.historicalParticipants == nil {
638			a.historicalParticipants = make(map[string]struct{})
639		}
640		if _, exists := a.historicalParticipants[trimmed]; exists {
641			return
642		}
643		a.historicalParticipants[trimmed] = struct{}{}
644		a.historicalParticipantCount = len(a.historicalParticipants)
645	}
646	
647	func aggregateMessageIsLatest(
648		aggregate *networkChannelAggregate,
649		message store.NetworkMessageEntry,
650	) bool {
651		return aggregate != nil &&
652			aggregate.lastMessageAt != nil &&
