670	func (h *BaseHandlers) createNetworkChannelSessions(
671		ctx context.Context,
672		channel string,
673		workspaceID string,
674		agentNames []string,
675	) ([]string, error) {
676		createdIDs := make([]string, 0, len(agentNames))
