949	func summarizeNetworkChannelKindCounts(
950		messages []store.NetworkMessageEntry,
951	) []contract.NetworkChannelKindCountPayload {
952		if len(messages) == 0 {
953			return nil
954		}
955		counts := make(map[string]int, len(messages))
956		for _, item := range messages {
957			kind := strings.TrimSpace(item.Kind)
958			if kind == "" {
959				continue
960			}
961			counts[kind]++
962		}
963		if len(counts) == 0 {
964			return nil
965		}
966		payload := make([]contract.NetworkChannelKindCountPayload, 0, len(counts))
967		for kind, count := range counts {
968			payload = append(payload, contract.NetworkChannelKindCountPayload{
969				Kind:  kind,
970				Count: count,
971			})
972		}
973		sort.Slice(payload, func(i int, j int) bool {
974			leftRank := networkKindSortRank(payload[i].Kind)
975			rightRank := networkKindSortRank(payload[j].Kind)
976			if leftRank != rightRank {
977				return leftRank < rightRank
978			}
979			return payload[i].Kind < payload[j].Kind
980		})
981		return payload
982	}
983	
984	func networkKindSortRank(kind string) int {
985		switch strings.TrimSpace(kind) {
986		case string(network.KindSay):
987			return 0
988		case string(network.KindDirect):
989			return 1
990		case string(network.KindReceipt):
991			return 2
992		case string(network.KindCapability):
993			return 3
994		case string(network.KindGreet):
995			return 4
996		case string(network.KindWhois):
997			return 5
998		case string(network.KindTrace):
999			return 6
1000		default:
1001			return 100
1002		}
1003	}
