1222		participants := make(map[string]struct{})
1223		for _, message := range messages {
1224			recordHistoricalParticipant(participants, message.PeerFrom)
1225			recordHistoricalParticipant(participants, message.PeerTo)
1226		}
1227		return len(participants)
