1293	func (s networkMessageHistorySummary) timelineViews(includePresence bool) []networkTimelineMessageView {
1294		if !includePresence {
1295			views := make([]networkTimelineMessageView, 0, len(s.conversation))
1296			for _, entry := range s.conversation {
1297				views = append(views, networkTimelineMessageView{entry: entry})
1298			}
1299			return views
1300		}
1301	
1302		views := make([]networkTimelineMessageView, 0, len(s.conversation)+len(s.presenceEpisodes))
1303		for _, entry := range s.conversation {
1304			views = append(views, networkTimelineMessageView{entry: entry})
1305		}
1306		views = append(views, s.presenceEpisodes...)
1307		sort.SliceStable(views, func(i int, j int) bool {
1308			left := views[i].entry.Timestamp.UTC()
1309			right := views[j].entry.Timestamp.UTC()
1310			if !left.Equal(right) {
1311				return left.Before(right)
1312			}
1313			return strings.TrimSpace(views[i].entry.MessageID) < strings.TrimSpace(views[j].entry.MessageID)
1314		})
1315		return views
1316	}
