1332		if strings.TrimSpace(current.entry.Channel) != strings.TrimSpace(next.Channel) {
1333			return false
1334		}
1335		if strings.TrimSpace(current.entry.PeerFrom) != strings.TrimSpace(next.PeerFrom) {
1336			return false
1337		}
1338		if strings.TrimSpace(current.entry.PeerTo) != strings.TrimSpace(next.PeerTo) {
1339			return false
1340		}
1341		return next.Timestamp.UTC().Sub(current.entry.Timestamp.UTC()) <= window
1342	}
