1489	func indexNetworkTimelineViewByMessageID(views []networkTimelineMessageView, messageID string) int {
1490		target := strings.TrimSpace(messageID)
1491		for index, view := range views {
1492			if strings.TrimSpace(view.entry.MessageID) == target {
1493				return index
1494			}
1495		}
1496		return -1
1497	}
