595	// Validate ensures the persisted network message is complete and internally consistent.
596	func (e NetworkMessageEntry) Validate() error {
597		if err := requireField(e.MessageID, "network message id"); err != nil {
598			return err
599		}
600		if err := requireField(e.Channel, "network message channel"); err != nil {
601			return err
602		}
603		if err := requireField(e.Direction, "network message direction"); err != nil {
604			return err
605		}
606		direction := strings.TrimSpace(e.Direction)
607		if direction != e.Direction {
608			return fmt.Errorf("store: unsupported network message direction %q", e.Direction)
609		}
610		switch direction {
611		case "sent", "received":
612		default:
613			return fmt.Errorf("store: unsupported network message direction %q", e.Direction)
614		}
615		if err := requireField(e.PeerFrom, "network message peer_from"); err != nil {
616			return err
617		}
618		if err := requireField(e.Kind, "network message kind"); err != nil {
619			return err
620		}
621		if len(e.Body) == 0 {
622			return fmt.Errorf("store: network message body is required")
623		}
624		if !json.Valid(e.Body) {
625			return fmt.Errorf("store: network message body must be valid JSON")
626		}
627		return nil
628	}
