137	function isGroupedWithPrevious(
138	  previous: NetworkTimelineMessage | undefined,
139	  current: NetworkTimelineMessage
140	) {
141	  if (!previous) {
142	    return false;
143	  }
144	
145	  if (previous.peer_from !== current.peer_from) {
146	    return false;
147	  }
148	
149	  const previousAt = new Date(previous.timestamp).getTime();
150	  const currentAt = new Date(current.timestamp).getTime();
151	  if (Number.isNaN(previousAt) || Number.isNaN(currentAt)) {
152	    return false;
153	  }
154	
155	  return currentAt - previousAt <= 5 * 60_000;
156	}
