262	function summarizeKindCounts(messages: NetworkTimelineMessage[]): NetworkRoomKindMetric[] {
263	  const counts = new Map<NetworkRoomKindMetric["kind"], number>();
264	
265	  for (const message of messages) {
266	    const kind = toNetworkKindFilter(message.kind);
267	    if (!kind) {
268	      continue;
269	    }
270	    counts.set(kind, (counts.get(kind) ?? 0) + 1);
271	  }
272	
273	  return [...counts.entries()]
274	    .map(([kind, count]) => ({ kind, count }))
275	    .sort((left, right) => right.count - left.count || left.kind.localeCompare(right.kind));
276	}
