538	function validateNetworkSearch(search: Record<string, unknown>): NetworkRouteSearch {
539	  const channel = normalizeSearchValue(search.channel);
540	  const peer = normalizeSearchValue(search.peer);
541	  const kindValue = normalizeSearchValue(search.kind);
542	  const normalizedKind =
543	    kindValue === "all" || (kindValue && toNetworkKindFilter(kindValue))
544	      ? (kindValue as NetworkKindFilter)
545	      : undefined;
546	
547	  return {
548	    channel,
549	    details: search.details === "closed" ? "closed" : undefined,
550	    kind: normalizedKind === "all" ? undefined : normalizedKind,
551	    peer: channel ? undefined : peer,
552	    presence: search.presence === "shown" ? "shown" : undefined,
553	  };
554	}
